import{_ as t,o as e,c as r,a3 as o}from"./chunks/framework.CH_GxKL1.js";const u=JSON.parse('{"title":"","description":"","frontmatter":{},"headers":[],"relativePath":"readings/Taming_Your_Amygdala/contexts/Chapter 09 - 杏仁核如何创建触发因素.md","filePath":"readings/Taming_Your_Amygdala/contexts/Chapter 09 - 杏仁核如何创建触发因素.md","lastUpdated":1781939005000}'),n={name:"readings/Taming_Your_Amygdala/contexts/Chapter 09 - 杏仁核如何创建触发因素.md"};function p(i,a,_,h,l,d){return e(),r("div",null,[...a[0]||(a[0]=[o('<h2 id="第-9-章" tabindex="-1">第 9 章 <a class="header-anchor" href="#第-9-章" aria-label="Permalink to &quot;第 9 章&quot;">​</a></h2><h2 id="杏仁核如何创建触发因素" tabindex="-1">杏仁核如何创建触发因素 <a class="header-anchor" href="#杏仁核如何创建触发因素" aria-label="Permalink to &quot;杏仁核如何创建触发因素&quot;">​</a></h2><p>到目前为止，我们的重点是帮助你更好地理解杏仁核，并学习管理其功能的方法。 虽然第 5 章重点讨论了杏仁核的语言，但它没有涉及沟通的一个重要方面：你需要学习的语言，以便向大脑的这一部分传达新的信息。 学习这种语言将让你能够教导你的杏仁核做出不同的反应。</p><p>杏仁核的学习能力正是它对于如此多的动物物种如此宝贵的原因。 杏仁核可以学会害怕物体和情境，作为保护我们免受前几代人不存在或我们生命早期不存在的威胁的手段。 也就是说，它能够适应动物所处的特定环境。 想象一只松鼠发现了一个围栏围起来的院子，里面满是橡果。 如果这只松鼠在那个院子里经历了负面事件，比如被一只狗追赶，那么松鼠的杏仁核将学会把那个院子当作危险的地方来反应。 每当松鼠靠近那个围栏院子时，它就会产生防御反应，为松鼠的战斗、逃跑或冻结做准备。 这种学习不涉及逻辑，也不需要因果联系。 松鼠只是同时经历了围栏院子和狗。</p><p>同样地，当你经历负面事件时，你的杏仁核可能会将与那个事件同时出现的那些情境或物体识别为危险的。 这是因为杏仁核被设计为基于<strong>关联</strong>从经验中学习。 当某个地点或物体与负面经验相关联（或配对）时，杏仁核通过在大脑中创建与恐惧相关的新神经连接，学会将该地点或物体当作危险的来反应（Quirk et al., 1995）。</p><p>神经元是大脑中的特定细胞，当两个不同的神经元同时被激活时，它们就会形成记忆（Hebb, 1949）。 你可能听过 Carla Shatz 的名言——&quot;一起放电的神经元会连接在一起&quot;（Doidge, 2007）——这意味着当神经元之间形成连接时，记忆就形成了。 以松鼠为例，两组不同的神经元同时开始放电：一组是处理身处围栏院子体验的神经元，另一组是处理被狗追赶体验的神经元。 这导致松鼠的杏仁核创建了神经回路——即形成了一种情绪记忆——将围栏院子与危险关联起来，使松鼠以恐惧来回应。</p><h3 id="理解触发因素" tabindex="-1">理解触发因素 <a class="header-anchor" href="#理解触发因素" aria-label="Permalink to &quot;理解触发因素&quot;">​</a></h3><p>为了学习杏仁核的语言，理解它如何创建<strong>触发因素</strong>非常重要，触发因素是指你的杏仁核已经与危险关联起来的事物，因此它们会引发焦虑和防御反应的其他方面。 在前面的例子中，围栏院子成了松鼠的触发因素。 各种物体、实体、地点、情境和感官刺激都可以成为触发因素，具体取决于一个人的经历。 有些人被拥挤的街道、教室或公交车触发，而另一些人则被某些声音和气味触发。 虽然你可能已经熟悉自己的触发因素，但你可能还没有意识到是杏仁核导致了你对这些触发因素所产生的焦虑。 下面的练习表将帮助你更好地识别和理解你的触发因素。</p><hr><h3 id="练习表" tabindex="-1">练习表 <a class="header-anchor" href="#练习表" aria-label="Permalink to &quot;练习表&quot;">​</a></h3><h3 id="识别你的触发因素" tabindex="-1">识别你的触发因素 <a class="header-anchor" href="#识别你的触发因素" aria-label="Permalink to &quot;识别你的触发因素&quot;">​</a></h3><p>在下面的空白处，列出你在遇到时常常引起焦虑的情境。 包括任何地点、经历、物体、人、动物、气味、声音等等。 制作你自己的触发因素列表将帮助你理解和应用你在本章中读到的内容。</p><hr><p>Copyright © 2022 Catherine M. Pittman. Taming Your Amygdala. All rights reserved.</p><hr><p>杏仁核在某个事物与负面事件关联时创建触发因素（图 7）。 当触发因素是在负面事件之前或与负面事件同时被体验到时，关联就发生了。 负面事件是指任何导致一个人产生负面身体或情绪反应的情境，如疼痛、不适、尴尬或痛苦。</p><p><strong>图 7</strong></p><p>例如，Jeremy 乘坐 Leo 的车时，另一辆车与他们相撞。 Leo 的车报废了，但幸运的是，Jeremy 和 Leo 只受了轻伤。 然而，这是一个非常痛苦的事件。 因为事故发生时 Jeremy 正坐在副驾驶座位上，坐副驾驶座位（触发因素）与事故（负面事件）被配对（关联）了。 尽管他以前坐车从来没有问题，但在事故之后，Jeremy 发现坐在任何车的副驾驶座位上现在都成了触发防御反应（包括焦虑）的触发因素。 Jeremy 仍然能够自己开车没有任何问题；只有当他试图坐在副驾驶座位上时才会感到焦虑。</p><p>请注意，触发因素<strong>不需要</strong>是危险的，也不需要是导致负面事件发生的原因。 触发因素只是与负面事件<strong>关联</strong>在一起。 这是因为当负面事件发生时，杏仁核会形成情绪记忆，创建将触发因素与恐惧或焦虑感连接起来的神经回路。 结果，当触发因素出现时，你的大脑被条件化地激活防御反应。 杏仁核也会在某个事物与愉快事件关联时创建积极的情绪记忆，比如你在球队赢得篮球赛季时穿的那双鞋。 由于穿着那双鞋时发生的积极事件，每当你看到它们时，你可能会感到积极的情绪，并且你可能不愿意丢弃它们。</p><p>杏仁核创建的情绪记忆与皮层形成的意识记忆不同。 你可能会有些触发因素看起来不合逻辑，因为你不记得自己曾经有过与该触发因素相关的负面经历。 如果是这样，那个事件的记忆并未存储在你的皮层中，但很显然你的杏仁核保留了一个记忆。 这是可能的，因为杏仁核形成记忆的方式与皮层完全分开。 你的皮层创建你所意识到的&quot;故事&quot;记忆，但杏仁核形成的是你情绪反应背后的记忆。 所以你的杏仁核仍然可以将这些触发因素记忆为危险的，即使你不记得原因。</p><p>这个过程被一位医生曾经对他的一个病人进行的一个小&quot;实验&quot;很好地说明了（Claparède, 1951）。 （请注意，这是一个我绝不会赞同的实验！） 这位病人患有科尔萨科夫综合征，这是一种痴呆症，患者会丧失在皮层中形成新记忆的能力。 因此，她不记得日复一日照顾她的医务人员，尽管她已经在医院住了多年。 每次医生进来时，他都不得不重新自我介绍，因为病人无法形成关于他的任何记忆。 为了测试病人的记忆，有一天，医生伸出手来与她握手，他用藏在手掌中的针刺了她一下。 在他下次来访时，当他走近病人并伸出手时，她恐惧地缩了回去。 他问她为什么不和他握手，她说她不知道。 虽然她不记得以前见过这位医生，但她不同意和他握手。 她的皮层不记得他，但她的杏仁核当然记得。</p><p>在你的一生中，你的杏仁核一直在记录着与负面事件相关联的任何物体、地点、人物或情境，尤其是那些导致负面情绪反应的事件。 它小心地将与该负面事件相关的一切储存在记忆中——用一个情绪标签标记它——这样每当你再次遇到那个触发因素时，你的杏仁核就会让你经历焦虑，甚至全面的防御反应。 此外，你可以在一个负面事件中形成多个触发因素。 例如，前面提到的经历过车祸的 Jeremy，可能不仅会对坐副驾驶座位产生反应，还可能对刹车尖叫或喇叭鸣响的声音产生反应，如果这些声音与事故相关联的话。</p><p>你的杏仁核甚至可以对那些你并非亲身经历、而是你观察到别人经历的负面事件创建触发因素。 比如说，你的母亲表现出对游泳的明显恐惧。 你的杏仁核也可以通过观察她的恐惧来学会害怕水。 你可以想象，几个世纪以来，学会害怕任何先前与你或他人发生的坏事相关联的事物，以及将别人以恐惧反应对待的事物识别为危险的，对人类来说是多么有用。 杏仁核是一个强大的保护者，因为它从经验中学习。 当你学习如何与你的杏仁核沟通时，记住这一点很重要。</p><p>现在你理解了杏仁核创建触发因素的方式和原因，你已经准备好开始更仔细地审视你的个人触发因素。 记住，触发因素和负面事件都是你可以看到、听到、感觉到、闻到或尝到的真实经历。 触发因素与负面事件的不同之处在于，你学会害怕触发因素，而负面事件是大多数人自然会产生负面反应的事情。 通常，触发因素会导致你知道不合逻辑的情绪，你认识到大多数其他人不会以你这样的方式来回应触发因素。 通过继续这本工作手册，你可以了解更多关于你的触发因素——包括如何减少它们对你的影响。</p><h3 id="绘制触发因素图" tabindex="-1">绘制触发因素图 <a class="header-anchor" href="#绘制触发因素图" aria-label="Permalink to &quot;绘制触发因素图&quot;">​</a></h3><p>识别杏仁核如何学会你的触发因素的一种方法是绘制触发因素图。 在某些情况下，你可能对与触发因素相关的负面事件有非常清晰的记忆。 例如，每当你看到黄蜂时，你可能会感到焦虑，因为你记得小时候被叮咬的疼痛。 在其他情况下，你可能不记得负面事件是什么，但你也许可以通过询问你生活中的其他人（如你的家人）来找到答案。 例如，一位在吉姆·克劳时代长大的黑人女性，童年时曾穿着她新买的红色泳衣被粗暴地拒绝进入一个种族隔离的游泳池。 她和她的母亲都因这一经历感到羞辱。 从那天起，这个女孩再也不穿那件泳衣了，她甚至不喜欢穿任何红色的衣服。 虽然她后来记不起为什么，但她的母亲可以告诉她，红色是如何成为她的一个触发因素的故事。</p><p>在下面的练习表中，你将有机会练习绘制一些假设的触发因素图，然后是你自己的一些触发因素。 请使用图 8 中的图示作为指南。</p><p><strong>图 8</strong></p><hr><h3 id="练习表-1" tabindex="-1">练习表 <a class="header-anchor" href="#练习表-1" aria-label="Permalink to &quot;练习表&quot;">​</a></h3><h3 id="绘制触发因素图-1" tabindex="-1">绘制触发因素图 <a class="header-anchor" href="#绘制触发因素图-1" aria-label="Permalink to &quot;绘制触发因素图&quot;">​</a></h3><p>通过识别每个情境中的触发因素和负面事件，练习绘制以下三个情境的图示。 使用图 8 中的模板来帮助你画出图示。 记住，触发因素不需要是负面事件的原因；它只需要与负面事件相关联。 这就是为什么有些恐惧甚至对那些拥有它的人来说也显得不合逻辑。</p><p>正确答案可在本章末尾找到。</p><ol><li><p>在被一个剃光头的男人性侵犯后，Rebecca 每当在有光头男性周围时就会感到焦虑。</p></li><li><p>Jason 在树林里散步时，突然起了雷暴。 他附近的一棵树被闪电击中，爆炸发出一声震耳欲聋的巨响。 现在 Jason 在树林里散步时会感到不舒服。</p></li><li><p>Heather 经常坐在大学教室的前排，因为她觉得这有助于她集中注意力。 在一位教授取笑她给出了错误答案之后，Heather 开始避免坐在前排。</p></li></ol><hr><p>Copyright © 2022 Catherine M. Pittman. Taming Your Amygdala. All rights reserved.</p><hr><p>现在你已经有了一些这些情境的练习，你已经准备好绘制你自己的触发因素图了。 回到你在&quot;识别你的触发因素&quot;练习表中创建的触发因素列表。 对于每个触发因素，考虑你从什么时候开始以焦虑或回避来回应这个触发因素。 你能记得一个在触发因素之后或与触发因素同时发生的负面事件吗？ 如果能，尝试画出这个关联。 通过识别创建了这个触发因素的情境，你可以更好地理解你的反应。 如果你记不起任何将触发因素与负面事件配对的情境，你可能想问问某个认识你很久的人（如家人），他们是否记得你有过关于该触发因素的任何经历。</p><p>触发因素 1：___________________</p><p>触发因素 2：___________________</p><p>触发因素 3：___________________</p><p>学习杏仁核基于关联的语言可以帮助你理解，你的杏仁核如何依靠过去的经验来决定它在今天将哪些物体或情境识别为危险的。 当你认识到杏仁核为何以这种方式反应时，它可以帮助你以新的眼光看待你的触发因素。 许多在我们童年时形成的恐惧仍然存在，尽管它们实际上不再有意义。 例如，我们中的许多人对听到自己的全名有厌恶感，因为它常常与惹上麻烦相关联：&quot;Catherine Marie！ 你干了什么？ ！&quot; 比尔·克林顿曾说过，他仍然不喜欢被称为 William。 一个能成为总统的人，仍然让他的全名触发负面情绪反应，这不是很有趣吗？</p><p>这些负面情绪反应将持续存在，直到杏仁核接收到改变其反应方式的新信息。 记住：一个触发因素必须与负面事件配对，杏仁核才能学会将该物体识别为危险的。 如果你将自己暴露于触发因素，同时确保它不与负面经历配对，杏仁核就能学会不再害怕该触发因素。 然而，人们常常以这样一种方式生活，使他们从不将杏仁核置于学习的情境中。 例如，一个被祖母的狗扑倒的男孩发展出对狗的恐惧，多年来一直回避狗，这阻止了他的杏仁核学到任何新东西。 只要没有新的与狗的经历发生，杏仁核就不会改变其反应。</p><p>相比之下，让我们考虑一个说明杏仁核中新学习过程的例子。 Jane 在与家人进行越野骑行时，她的马受惊并向侧面跳跃，她从马上摔了下来。 她骑在母亲的马上返回马厩，母亲就坐在她身后。 Jane 的家人继续鼓励她与他们一起在小径上骑马，但她很害怕，不愿意去。 最后，Jane 的妈妈给他们家最温顺的马上了鞍，让 Jane 只是坐在马上，母亲牵着马在马厩周围走。 尽管 Jane 起初很痛苦，但在几次训练后，她变得足够平静，可以自己拿缰绳了。 再经过几次这样的训练，Jane 说她愿意骑这匹马去小径上了。 最终，Jane 的妈妈甚至可以鼓励她尝试骑那匹她曾经摔下来的马。</p><p>图 9 说明了用于帮助 Jane 克服对马的恐惧的过程。 对于 Jane 来说，骑马与她从马上摔下来的负面经历相关联。 由于这种关联，骑马开始引发 Jane 的防御反应，导致焦虑、恐惧和强烈的逃离情境的欲望。 Jane 的杏仁核学会了将骑马识别为危险的，这使其成为她的触发因素。 但当 Jane 的母亲让她骑上那匹温顺的马时，她为 Jane 的杏仁核提供了一个新的学习机会。 她通过确保每次骑行都愉快而安全，反复将骑马的经历与积极或中性的经历配对，这使得新的学习得以发生。 像这样的<strong>渐进式暴露</strong>——我们确保没有任何负面事件发生——是教导杏仁核某个触发因素是安全的最佳方式。</p><p><strong>图 9</strong></p><p>正如我们讨论过的，你可能不知道一开始使某个事物成为触发因素的原始配对。 但这没关系——你不需要记住负面经历就能形成新的经历来安抚你的杏仁核。 如果一个男孩害怕棒球棒，他是因为在少年棒球联盟比赛中被球棒意外击中而形成这个触发因素，还是因为他父亲用球棒打他作为惩罚，或者是因为一个邻居恶霸用球棒威胁他，这都没关系。 在每种情况下，改变杏仁核反应的最佳方法都是反复将他暴露于棒球棒，同时没有任何负面事件发生。 最终，这将教会他的杏仁核做出不同的反应，随着新记忆的形成，杏仁核的激活会减少（Roy et al., 2014）。 这个过程被称为<strong>暴露疗法</strong>，将是下一章的重点。</p><h3 id="识别阻碍你目标的触发因素" tabindex="-1">识别阻碍你目标的触发因素 <a class="header-anchor" href="#识别阻碍你目标的触发因素" aria-label="Permalink to &quot;识别阻碍你目标的触发因素&quot;">​</a></h3><p>在进入下一章之前，我想让你考虑一下，如果你的杏仁核对某些触发因素不产生防御反应，你的生活会有什么不同。 你能够达成什么目标？ 使用下面的练习表来帮助你识别那些阻碍你实现目标的触发因素，因为这些是你想要首先努力克服的触发因素。 例如，亚利桑那州的一名景观设计师可能发现她对蛇的恐惧限制了她进行植物调查的能力，无法在项目现场完成工作。 另一方面，纽约市一位同样害怕蛇的时装设计师可能不需要减少这种恐惧，因为它不会干扰她的日常生活或职业追求。 你会想要专注于那些阻止你完成自己所设定目标的触发因素。 通过努力克服这些触发因素，你正在改变杏仁核，这将对你的生活产生影响。</p><hr><h3 id="练习表-2" tabindex="-1">练习表 <a class="header-anchor" href="#练习表-2" aria-label="Permalink to &quot;练习表&quot;">​</a></h3><h3 id="识别阻碍你目标的触发因素-1" tabindex="-1">识别阻碍你目标的触发因素 <a class="header-anchor" href="#识别阻碍你目标的触发因素-1" aria-label="Permalink to &quot;识别阻碍你目标的触发因素&quot;">​</a></h3><p>回顾第 3 章中的&quot;重要目标&quot;列表，确定现在对你最重要的三到四个目标。 你可能想重新评估你之前分配的评分，尤其是如果你的情况或优先事项自完成那个练习表以来发生了变化。</p><p>然后回顾本章的&quot;识别你的触发因素&quot;练习表，考虑这些触发因素中是否有任何一个正在干扰你的目标。 哪些目标被你的杏仁核对这些触发因素的反应所阻碍？ 这可以帮助你确定哪些触发因素是你想要首先关注的。 当你考虑你的目标时，你甚至可能想到更多的触发因素添加到你的列表中。 例如，直到 Anton 想到他面试新工作的目标时，他才意识到与陌生人进行直接眼神接触这个触发因素正在干扰这个目标。</p><p>下面的图表将帮助你完成这个过程。 写下至少三个你想要实现的目标以及阻碍这些目标的触发因素。 然后使用第 1 章中的&quot;评估你的焦虑&quot;练习表来评估你与每个触发因素相关时通常经历的焦虑程度。</p><table tabindex="0"><thead><tr><th>目标</th><th>阻碍目标的触发因素</th><th>焦虑评分</th></tr></thead><tbody><tr><td></td><td></td><td></td></tr><tr><td></td><td></td><td></td></tr><tr><td></td><td></td><td></td></tr></tbody></table><hr><p>Copyright © 2022 Catherine M. Pittman. Taming Your Amygdala. All rights reserved.</p><hr><h3 id="绘制触发因素图-练习表答案" tabindex="-1">&quot;绘制触发因素图&quot;练习表答案 <a class="header-anchor" href="#绘制触发因素图-练习表答案" aria-label="Permalink to &quot;&quot;绘制触发因素图&quot;练习表答案&quot;">​</a></h3><ol><li><p><strong>触发因素：</strong> 光头/剃光的头</p><p><strong>负面事件：</strong> 性侵犯</p></li><li><p><strong>触发因素：</strong> 树/树林</p><p><strong>负面事件：</strong> 闪电/爆炸</p></li><li><p><strong>触发因素：</strong> 坐在前排</p><p><strong>负面事件：</strong> 被取笑</p></li></ol>',61)])])}const g=t(n,[["render",p]]);export{u as __pageData,g as default};
